use actix_web::{web, App, HttpResponse, HttpServer};
use std::path::{Path, PathBuf};

const UPLOADS_DIR: &str = "/uploads";

async fn get_file(path: web::Path<String>) -> Result<HttpResponse, actix_web::error::Error> {
    let uploads_dir = Path::new(UPLOADS_DIR);
    let file_path = uploads_dir.join(&path);

    if !file_path.is_absolute() || !file_path.starts_with(uploads_dir) {
        return Err(actix_web::error::ErrorNotFound("Invalid path"));
    }

    match std::fs::read_to_string(file_path) {
        Ok(content) => Ok(HttpResponse::Ok().body(content)),
        Err(_) => Err(actix_web::error::ErrorInternalServerError("Failed to read file")),
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new()
            .service(
                web::resource("/upload/{filename}")
                    .route(web::get().to(get_file))
                    .route(web::head().to(|_| HttpResponse::Ok())),
            )
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}